public class MassActionButtonExecutor implements Runnable {
    private NUIForm form;
    private int buttonId = -1;
    private RagicBundle bundle;
    private Map<String, JSONObject> browsingData = new HashMap<>();
    private User user;
    private Log logger = Log.createStandardLog().setLevel(Log.WARN);
    
    public MassActionButtonExecutor(NUIForm form, int buttonId, RagicBundle bundle, Map<String, JSONObject> browsingData, User user) {
        this.form = form;
        this.buttonId = buttonId;
        this.bundle = bundle;
        this.browsingData = browsingData;
        this.user = user;
    }
    
    public void run() {
        ActionButton buttonJSON = this.form.getActionButtons().get("" + buttonId);
        if(buttonJSON == null) return;
        boolean needApproval = buttonJSON.ifNeedApproval();
        String buttonName = buttonJSON.getName();
        
        ServiceExecuteEngine see = new ServiceExecuteEngine(this.form.getApname(), this.form);
        
        // Register Long term task
        LongTermTask ltt = ThreadManager.getInstance().addTask(Thread.currentThread(),this.form.getApname(), "Mass Action Button: " + buttonName + " (" + this.form.getUrl() + ")");
        
        // Register running service
        MassActionButtonRunningService rs = new MassActionButtonRunningService(this.form.getUrl());
        RunningServiceRegister.getInstance().addService(this.form.getApname(), rs);
        
        // Update system task progress
        SystemTaskProgress.setStatus(this.form.getApname(),Const.STP_ACTIONBUTTON, bundle.getString("massActionButton_execution_start", new String[] {buttonName}), -1, SystemTaskProgress.Status.PROCESSING);
        
        BDBMgr mgr = BDBMgr.getInstance(this.form.getApname());
        try {

            // Lock sheet
            EntryLocker lock= mgr.lockSheet(this.form.getPath(), form.getFormName(), user, EntryLocker.API);
            if(lock!=null) return;
            
            int executedCount = 0;
            for(Map.Entry<String, JSONObject> e: browsingData.entrySet()) {
                String key = e.getKey();
                JSONObject data = e.getValue();
                try {
                    if(needApproval) {
                        String approvalStatus = data.optString(DConst.WF_STATUS + "", null);
                        if(!"F".equals(approvalStatus)) continue;
                    }
	                int rootNodeId = Integer.parseInt(key);
	                see.setTrigger(new ActionButtonTrigger(this.form.getApname(), this.form.getPath(), Integer.parseInt(this.form.getSheetIndex()), rootNodeId, buttonName));
	                String exescript=this.form.getSheetscope() + Encoder.unformatNUIAttr(this.form.getButtonScript(buttonId));
	                
	                ScriptResponse sr = see.executeScript(user, bundle, exescript,null,rootNodeId);
	                executedCount++;
	                
	                // Update system task progress
	                SystemTaskProgress.setStatus(this.form.getApname(),Const.STP_ACTIONBUTTON, bundle.getString("massActionButton_executed", new String[] {buttonName, "" + executedCount}), -1, SystemTaskProgress.Status.PROCESSING);
                
                    Thread.sleep(EXEUTION_SLEEP_MILLISECOND);
                } catch(Exception e_execFailed) {
                    logger.warn("Mass action button execution failed [form=" + this.form.getUrl() + ", button=" + buttonName + ", recordRootNodeId=" + key + "]");
                    logger.warn(e_execFailed);
                }
            }
            
        } finally {
            // Remove running service
            RunningServiceRegister.getInstance().removeService(this.form.getApname(), rs);
            
            // Unlock sheet
            mgr.unlockSheet(this.form.getPath(), form.getFormName());
            
            // Update system task progress
            SystemTaskProgress.setStatus(this.form.getApname(),Const.STP_ACTIONBUTTON, bundle.getString("massActionButton_execution_end", new String[] {buttonName}), -1, SystemTaskProgress.Status.DONE);
            
            // Remove long term task
            ThreadManager.getInstance().removeTask(ltt);
        }
        
    }
}


private JSONArray getCheckedRootNodeIds(HttpServletRequest request) {
    JSONArray checkedRootNodeIds = null;
    try {
        checkedRootNodeIds = new JSONArray(request.getParameter("checkedNodeIds"));
    } catch(Exception ignored) {}
    return checkedRootNodeIds;
}

